// ═══════════════════════════════════════
// 觀察清單設定
// ═══════════════════════════════════════
const WATCHLIST = [
  { symbol: 'OKLO', name: 'Oklo Inc.', sector: 'Nuclear Energy' },
  { symbol: 'CRWD', name: 'CrowdStrike', sector: 'Cybersecurity' },
  { symbol: 'NVDA', name: 'NVIDIA', sector: 'Semiconductors' },
  { symbol: 'AAPL', name: 'Apple Inc.', sector: 'Consumer Tech' },
];

// 輸出每檔股票作為獨立 item
return WATCHLIST.map(stock => ({ json: stock }));

// ═══════════════════════════════════════
// 技術指標計算引擎
// RSI(14) + 布林通道(20,2) + MA交叉
// ═══════════════════════════════════════

const item = $input.first().json;
let chartData;

try {
  const body = typeof item.body === 'string' ? JSON.parse(item.body) : item.body;
  chartData = body.chart?.result?.[0];
} catch(e) {
  return [{ json: { error: 'Failed to parse chart data', symbol: item.symbol || 'unknown' } }];
}

if (!chartData) {
  return [{ json: { error: 'No chart data', symbol: item.symbol || 'unknown' } }];
}

const closes = chartData.indicators?.quote?.[0]?.close?.filter(c => c !== null) || [];
const highs = chartData.indicators?.quote?.[0]?.high?.filter(h => h !== null) || [];
const lows = chartData.indicators?.quote?.[0]?.low?.filter(l => l !== null) || [];
const volumes = chartData.indicators?.quote?.[0]?.volume?.filter(v => v !== null) || [];
const timestamps = chartData.timestamp || [];

const symbol = chartData.meta?.symbol || 'unknown';
const currentPrice = closes[closes.length - 1] || 0;
const prevClose = closes[closes.length - 2] || currentPrice;

// --- RSI(14) ---
function calcRSI(prices, period = 14) {
  if (prices.length < period + 1) return null;
  let gains = 0, losses = 0;
  for (let i = prices.length - period; i < prices.length; i++) {
    const diff = prices[i] - prices[i - 1];
    if (diff > 0) gains += diff;
    else losses += Math.abs(diff);
  }
  const avgGain = gains / period;
  const avgLoss = losses / period;
  if (avgLoss === 0) return 100;
  const rs = avgGain / avgLoss;
  return +(100 - 100 / (1 + rs)).toFixed(2);
}

// --- 布林通道(20,2) ---
function calcBollinger(prices, period = 20, mult = 2) {
  if (prices.length < period) return null;
  const slice = prices.slice(-period);
  const mean = slice.reduce((a, b) => a + b, 0) / period;
  const variance = slice.reduce((a, b) => a + (b - mean) ** 2, 0) / period;
  const std = Math.sqrt(variance);
  return {
    upper: +(mean + mult * std).toFixed(2),
    middle: +mean.toFixed(2),
    lower: +(mean - mult * std).toFixed(2),
  };
}

// --- 均線 ---
function calcMA(prices, period) {
  if (prices.length < period) return null;
  const slice = prices.slice(-period);
  return +(slice.reduce((a, b) => a + b, 0) / period).toFixed(2);
}

// --- MACD(12,26,9) ---
function calcEMA(prices, period) {
  if (prices.length < period) return null;
  const k = 2 / (period + 1);
  let ema = prices.slice(0, period).reduce((a, b) => a + b, 0) / period;
  for (let i = period; i < prices.length; i++) {
    ema = prices[i] * k + ema * (1 - k);
  }
  return +ema.toFixed(2);
}

const rsi = calcRSI(closes, 14);
const bollinger = calcBollinger(closes, 20, 2);
const ma5 = calcMA(closes, 5);
const ma10 = calcMA(closes, 10);
const ma20 = calcMA(closes, 20);
const ma50 = calcMA(closes, 50);
const ma60 = calcMA(closes, 60);
const ema12 = calcEMA(closes, 12);
const ema26 = calcEMA(closes, 26);
const macd = ema12 && ema26 ? +(ema12 - ema26).toFixed(2) : null;

// --- 成交量分析 ---
const avgVolume20 = volumes.length >= 20
  ? Math.round(volumes.slice(-20).reduce((a, b) => a + b, 0) / 20)
  : null;
const latestVolume = volumes[volumes.length - 1] || 0;
const volumeRatio = avgVolume20 ? +(latestVolume / avgVolume20).toFixed(2) : null;

// --- 買點三條件判斷 ---
const buySignals = {
  rsiBelow20: rsi !== null && rsi < 20,
  belowBollingerLower: bollinger !== null && currentPrice <= bollinger.lower,
  belowMA50: ma50 !== null && currentPrice < ma50,
  rsiBelow30: rsi !== null && rsi < 30,
  aboveMA60: ma60 !== null && currentPrice > ma60,
};

const buyScore = [buySignals.rsiBelow20, buySignals.belowBollingerLower, buySignals.belowMA50].filter(Boolean).length;

return [{
  json: {
    symbol,
    currentPrice: +currentPrice.toFixed(2),
    prevClose: +prevClose.toFixed(2),
    changePercent: +(((currentPrice - prevClose) / prevClose) * 100).toFixed(2),
    technical: {
      rsi,
      bollinger,
      ma5, ma10, ma20, ma50, ma60,
      ema12, ema26, macd,
      volumeRatio,
      avgVolume20,
      latestVolume,
    },
    buySignals,
    buyScore,
    dataPoints: closes.length,
    lastUpdate: new Date().toISOString(),
  }
}];

// ═══════════════════════════════════════
// 基本面數據解析
// 5:3:2 體質分析引擎
// ═══════════════════════════════════════

const item = $input.first().json;
let data;

try {
  const body = typeof item.body === 'string' ? JSON.parse(item.body) : item.body;
  data = body.quoteSummary?.result?.[0];
} catch(e) {
  return [{ json: { error: 'Failed to parse fundamentals', raw: item } }];
}

if (!data) {
  return [{ json: { error: 'No fundamental data available' } }];
}

const fd = data.financialData || {};
const ks = data.defaultKeyStatistics || {};
const rec = data.recommendationTrend?.trend?.[0] || {};
const inst = data.institutionOwnership?.ownershipList || [];

// 提取關鍵指標
const fundamentals = {
  // 價值面
  pe: ks.trailingPE?.raw || null,
  forwardPE: ks.forwardPE?.raw || null,
  eps: ks.trailingEps?.raw || null,
  bookValue: ks.bookValue?.raw || null,
  priceToBook: ks.priceToBook?.raw || null,
  roe: fd.returnOnEquity?.raw ? +(fd.returnOnEquity.raw * 100).toFixed(2) : null,

  // 成長面
  revenueGrowth: fd.revenueGrowth?.raw ? +(fd.revenueGrowth.raw * 100).toFixed(2) : null,
  earningsGrowth: fd.earningsGrowth?.raw ? +(fd.earningsGrowth.raw * 100).toFixed(2) : null,

  // 獲利面
  grossMargins: fd.grossMargins?.raw ? +(fd.grossMargins.raw * 100).toFixed(2) : null,
  operatingMargins: fd.operatingMargins?.raw ? +(fd.operatingMargins.raw * 100).toFixed(2) : null,
  profitMargins: fd.profitMargins?.raw ? +(fd.profitMargins.raw * 100).toFixed(2) : null,

  // 現金流
  freeCashflow: fd.freeCashflow?.raw || null,
  operatingCashflow: fd.operatingCashflow?.raw || null,
  totalRevenue: fd.totalRevenue?.raw || null,

  // 目標價
  targetMeanPrice: fd.targetMeanPrice?.raw || null,
  targetHighPrice: fd.targetHighPrice?.raw || null,
  targetLowPrice: fd.targetLowPrice?.raw || null,
  currentPrice: fd.currentPrice?.raw || null,
  recommendationKey: fd.recommendationKey || null,

  // 分析師推薦
  analystBuy: (rec.strongBuy || 0) + (rec.buy || 0),
  analystHold: rec.hold || 0,
  analystSell: (rec.sell || 0) + (rec.strongSell || 0),
};

// 40% 法則
const rule40 = (fundamentals.revenueGrowth || 0) + (fundamentals.operatingMargins || 0);

// 5:3:2 體質計算
let valueScore = 0, growthScore = 0, specScore = 0;

// 價值評分
if (fundamentals.eps > 0) valueScore += 25;
if (fundamentals.pe && fundamentals.pe < 30) valueScore += 20;
else if (fundamentals.pe && fundamentals.pe < 60) valueScore += 10;
if (fundamentals.roe && fundamentals.roe > 15) valueScore += 20;
if (fundamentals.grossMargins && fundamentals.grossMargins > 40) valueScore += 15;
if (fundamentals.operatingMargins && fundamentals.operatingMargins > 20) valueScore += 20;

// 成長評分
if (fundamentals.revenueGrowth > 40) growthScore += 40;
else if (fundamentals.revenueGrowth > 20) growthScore += 25;
else if (fundamentals.revenueGrowth > 10) growthScore += 15;
if (rule40 > 40) growthScore += 30;
else if (rule40 > 25) growthScore += 15;

// 投機評分
if (!fundamentals.eps || fundamentals.eps < 0) specScore += 30;
if (fundamentals.pe && fundamentals.pe > 80) specScore += 20;
if (!fundamentals.revenueGrowth || fundamentals.revenueGrowth <= 0) specScore += 15;
if (!fundamentals.roe || fundamentals.roe < 0) specScore += 15;

const total = Math.max(valueScore + growthScore + specScore, 1);
const composition = {
  value: Math.round(valueScore / total * 100),
  growth: Math.round(growthScore / total * 100),
  speculative: Math.round(specScore / total * 100),
};
const sum = composition.value + composition.growth + composition.speculative;
if (sum !== 100) composition.value += (100 - sum);

const dominant = Object.entries(composition).sort((a, b) => b[1] - a[1])[0][0];

// 籌碼面 - 機構持股
const topInstitutions = inst.slice(0, 5).map(i => ({
  name: i.organization || 'Unknown',
  shares: i.position?.raw || 0,
  changePercent: i.pctChange?.raw ? +(i.pctChange.raw * 100).toFixed(2) : 0,
}));

return [{
  json: {
    fundamentals,
    rule40: +rule40.toFixed(2),
    composition,
    dominant,
    topInstitutions,
    lastUpdate: new Date().toISOString(),
  }
}];

// ═══════════════════════════════════════
// 新聞提取 (從 RSS XML 解析)
// ═══════════════════════════════════════

const item = $input.first().json;
const body = item.body || item.data || '';

// 簡單 XML 解析提取標題
const titleRegex = /<title><!\[CDATA\[(.+?)\]\]><\/title>|<title>(.+?)<\/title>/g;
const titles = [];
let match;
let count = 0;

while ((match = titleRegex.exec(body)) !== null && count < 10) {
  const title = match[1] || match[2] || '';
  if (title && !title.includes('Google News') && title.length > 10) {
    titles.push(title.trim());
    count++;
  }
}

return [{
  json: {
    headlines: titles,
    headlineCount: titles.length,
    rawForSentiment: titles.join(' | '),
  }
}];

