// ═══════════════════════════════════════
// 十二宮格坐標定位引擎
// 整合：技術面 + 基本面 + 消息面
// ═══════════════════════════════════════

const items = $input.all();

// 收集所有維度的數據
let technical = {}, fundamentalData = {}, sentiment = {};

for (const item of items) {
  const d = item.json;
  if (d.technical) technical = d;
  if (d.fundamentals) fundamentalData = d;
  if (d.sentiment || d.headlines) {
    // 解析 Claude 回傳的情緒
    try {
      if (d.content && d.content[0]) {
        const text = d.content[0].text || '';
        const clean = text.replace(/```json|```/g, '').trim();
        sentiment = JSON.parse(clean);
      } else if (d.headlines) {
        sentiment = { sentiment: 'neutral', score: 50, themes: [], summary: 'No analysis' };
      }
    } catch(e) {
      sentiment = { sentiment: 'neutral', score: 50, themes: [], summary: 'Parse failed' };
    }
  }
}

const symbol = technical.symbol || 'UNKNOWN';
const price = technical.currentPrice || 0;
const rsi = technical.technical?.rsi;
const bollinger = technical.technical?.bollinger;
const composition = fundamentalData.composition || { value: 33, growth: 33, speculative: 34 };
const dominant = fundamentalData.dominant || 'growth';
const rule40 = fundamentalData.rule40 || 0;
const targetPrice = fundamentalData.fundamentals?.targetMeanPrice || price;

// ═══ 坐標判定邏輯 ═══
let phase = 'evaluate';

// 買進條件 (學長的三條件)
const buyConditions = [
  price <= targetPrice,                                    // 股價 ≤ 目標價
  rsi !== null && rsi < 20,                               // RSI < 20
  bollinger && price <= bollinger.lower,                   // 觸及布林下軌
];
const buyScore = buyConditions.filter(Boolean).length;

// 賣出條件
const sellConditions = [
  rsi !== null && rsi > 70,                               // RSI > 70 超買
  bollinger && price >= bollinger.upper,                   // 觸及布林上軌
  sentiment.sentiment === 'negative' && sentiment.score > 70, // 強烈負面新聞
];
const sellScore = sellConditions.filter(Boolean).length;

// 坐標判定
if (buyScore >= 2) phase = 'buy';
else if (sellScore >= 2) phase = 'sell';
else if (rsi && rsi > 30 && rsi < 70 && technical.changePercent > -2) phase = 'hold';
else phase = 'evaluate';

// ═══ 買入安全等級 ═══
let buyAlert = 'none';
if (buyScore === 3) buyAlert = 'strong_buy';
else if (buyScore === 2) buyAlert = 'watch';

// ═══ AI 投資建議生成 ═══
const insights = [];

insights.push(`📍 ${symbol} 坐標：${phase === 'evaluate' ? '評估' : phase === 'buy' ? '買進' : phase === 'hold' ? '持有' : '賣出'}-${dominant === 'value' ? '價值' : dominant === 'growth' ? '成長' : '投機'}`);
insights.push(`📐 體質：價值${composition.value}% 成長${composition.growth}% 投機${composition.speculative}%`);

if (rule40 > 40) insights.push(`✅ 40%法則通過 (${rule40}%)`);
else if (rule40 > 0) insights.push(`⚠️ 40%法則未通過 (${rule40}%)`);

if (rsi < 20) insights.push(`🔥 RSI ${rsi} 超賣！留意反彈買點`);
else if (rsi < 30) insights.push(`📉 RSI ${rsi} 偏低，接近買入區`);
else if (rsi > 70) insights.push(`⚠️ RSI ${rsi} 超買，注意獲利了結`);
else if (rsi) insights.push(`📊 RSI ${rsi} 中性區間`);

if (bollinger) {
  if (price <= bollinger.lower) insights.push(`📊 股價觸及布林下軌 $${bollinger.lower}`);
  if (price >= bollinger.upper) insights.push(`📊 股價觸及布林上軌 $${bollinger.upper}`);
}

if (buyScore === 3) insights.push(`🎯 三條件全部滿足！最安全買點！`);
else if (buyScore === 2) insights.push(`💡 ${buyScore}/3 買入條件觸發，接近買點`);

if (sentiment.summary) insights.push(`📰 ${sentiment.summary}`);

return [{
  json: {
    symbol,
    price,
    changePercent: technical.changePercent,

    // 十二宮格坐標
    gridPosition: {
      phase,
      type: dominant,
      label: `${phase === 'evaluate' ? '評估' : phase === 'buy' ? '買進' : phase === 'hold' ? '持有' : '賣出'}-${dominant === 'value' ? '價值' : dominant === 'growth' ? '成長' : '投機'}`,
    },

    // 體質分析
    composition,
    rule40,

    // 技術指標
    technical: {
      rsi: technical.technical?.rsi,
      bollinger: technical.technical?.bollinger,
      ma50: technical.technical?.ma50,
      ma60: technical.technical?.ma60,
      macd: technical.technical?.macd,
      volumeRatio: technical.technical?.volumeRatio,
    },

    // 基本面
    fundamentals: fundamentalData.fundamentals || {},

    // 籌碼面
    topInstitutions: fundamentalData.topInstitutions || [],

    // 消息面
    sentiment,

    // 買賣信號
    buySignals: {
      conditions: buyConditions,
      score: buyScore,
      alert: buyAlert,
    },
    sellSignals: {
      conditions: sellConditions,
      score: sellScore,
    },

    // AI 建議
    insights,

    timestamp: new Date().toISOString(),
  }
}];

// ═══════════════════════════════════════
// 輸出：儲存到 Google Sheet 或本地 JSON
// ═══════════════════════════════════════

const data = $input.first().json;

// 整理成扁平化格式方便存入 Sheet
const row = {
  date: new Date().toISOString().split('T')[0],
  symbol: data.symbol,
  price: data.price,
  change: data.changePercent,

  // 坐標
  gridPhase: data.gridPosition?.phase,
  gridType: data.gridPosition?.type,
  gridLabel: data.gridPosition?.label,

  // 體質
  valuePercent: data.composition?.value,
  growthPercent: data.composition?.growth,
  specPercent: data.composition?.speculative,
  rule40: data.rule40,

  // 技術面
  rsi: data.technical?.rsi,
  bollingerUpper: data.technical?.bollinger?.upper,
  bollingerMiddle: data.technical?.bollinger?.middle,
  bollingerLower: data.technical?.bollinger?.lower,
  ma50: data.technical?.ma50,
  volumeRatio: data.technical?.volumeRatio,

  // 基本面
  pe: data.fundamentals?.pe,
  eps: data.fundamentals?.eps,
  roe: data.fundamentals?.roe,
  revenueGrowth: data.fundamentals?.revenueGrowth,
  operatingMargin: data.fundamentals?.operatingMargins,
  targetPrice: data.fundamentals?.targetMeanPrice,

  // 信號
  buyScore: data.buySignals?.score,
  buyAlert: data.buySignals?.alert,
  sellScore: data.sellSignals?.score,

  // 情緒
  sentimentScore: data.sentiment?.score,
  sentimentLabel: data.sentiment?.sentiment,

  // AI
  insights: data.insights?.join(' | '),
};

return [{ json: row }];

// ═══════════════════════════════════════
// 買點警報檢查
// 滿足 2/3 條件時觸發通知
// ═══════════════════════════════════════

const data = $input.first().json;

if (data.buyScore >= 2) {
  return [{
    json: {
      alert: true,
      symbol: data.symbol,
      price: data.price,
      buyScore: data.buyScore,
      gridLabel: data.gridLabel,
      message: `🔥 ${data.symbol} 買點警報！\n價格: $${data.price} (${data.change > 0 ? '+' : ''}${data.change}%)\n坐標: ${data.gridLabel}\n買入條件: ${data.buyScore}/3 觸發\nRSI: ${data.rsi || 'N/A'}\n\n${data.insights || ''}`,
    }
  }];
}

return [{ json: { alert: false, symbol: data.symbol } }];
